import apiClient from './apiClient';
import type { School, CreateSchoolData, UpdateSchoolData, PaginationParams, PaginatedResponse } from '@/types/api';

export class SchoolService {
  private static readonly BASE_PATH = '/schools';

  static async getSchools(params?: PaginationParams): Promise<PaginatedResponse<School>> {
    const response = await apiClient.get<PaginatedResponse<School>>(this.BASE_PATH, { params });
    return response.data as PaginatedResponse<School>;
  }

  static async getSchool(id: string): Promise<School> {
    const response = await apiClient.get<School>(`${this.BASE_PATH}/${id}`);
    return response.data as School;
  }

  static async createSchool(data: CreateSchoolData): Promise<School> {
    const response = await apiClient.post<School>(this.BASE_PATH, data);
    return response.data as School;
  }

  static async updateSchool(id: string, data: UpdateSchoolData): Promise<School> {
    const response = await apiClient.put<School>(`${this.BASE_PATH}/${id}`, data);
    return response.data as School;
  }

  static async deleteSchool(id: string): Promise<void> {
    await apiClient.delete(`${this.BASE_PATH}/${id}`);
  }

  static async searchSchools(query: string, params?: PaginationParams): Promise<PaginatedResponse<School>> {
    const response = await apiClient.get<PaginatedResponse<School>>(`${this.BASE_PATH}/search`, {
      params: { q: query, ...params }
    });
    return response.data as PaginatedResponse<School>;
  }

  static async getSchoolStats(id: string) {
    const response = await apiClient.get<any>(`${this.BASE_PATH}/${id}/stats`);
    return response.data;
  }
}